class Solution:
    def solve(self, s: str) -> bool:
        S = []
        for c in s:
            if c == '+' or c == '*' or c == '^':
                while S and S[-1] != '*':
                    S.pop()
                S.append(c)
            else:
                S.append(c)
        return len(S) > 0

def main():
    import sys
    s = sys.stdin.readline().strip()
    print('Yes' if Solution().solve(s) else 'No')

